// @/src/hooks/useNotification.ts
import { createContext, useContext, useState } from 'react';
import { NotificationProps } from '../helpers/notification.helpers';

interface NotificationContextValue {
  openNotification: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextValue | null>(null);

const useNotification = (): NotificationContextValue => {
  const notificationElem = useContext(NotificationContext);
  if (!notificationElem) {
    throw new Error('useNotification must be used within a NotificationContext');
  }

  const openNotification = async (props: NotificationProps) => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    await notificationElem.open({
      heading,
      subheading,
      type,
    });
  };

  return { openNotification };
};

export default useNotification;
